using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

// ── Shared state ───────────────────────────────────────────────────────────────
var notebook = new List<(DateTime Timestamp, string Content)>();
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// ── Tool implementations ───────────────────────────────────────────────────────

[Description("Search the web for a query and return relevant result snippets.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    try
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: {query}\n");

        // Instant-answer abstract
        var abstractText = root.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            var source = root.GetProperty("AbstractSource").GetString();
            sb.AppendLine($"## Summary ({source})");
            sb.AppendLine(abstractText);
            sb.AppendLine();
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            var count = 0;
            foreach (var topic in topics.EnumerateArray())
            {
                if (topic.TryGetProperty("Text", out var text)
                    && !string.IsNullOrWhiteSpace(text.GetString()))
                {
                    sb.AppendLine($"- {text.GetString()}");
                    if (++count >= 8) break;
                }
            }
        }

        var result = sb.ToString();
        return result.Length > 60
            ? result
            : $"No detailed results found for '{query}'. Try rephrasing or using different keywords.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Save a research note. Use this to record key findings, facts, or insights discovered during research.")]
string SaveNote(
    [Description("The content of the note to save")] string content)
{
    notebook.Add((DateTime.UtcNow, content));
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"  📝 Note #{notebook.Count} saved ({content.Length} chars)");
    Console.ResetColor();
    return $"Note #{notebook.Count} saved successfully.";
}

[Description("Retrieve all saved research notes collected so far.")]
string GetNotes()
{
    if (notebook.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notebook.Count; i++)
    {
        sb.AppendLine($"--- Note #{i + 1} [{notebook[i].Timestamp:HH:mm:ss UTC}] ---");
        sb.AppendLine(notebook[i].Content);
        sb.AppendLine();
    }
    return sb.ToString();
}

// ── Build the AI client with automatic tool invocation ─────────────────────────
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// ── System prompt ──────────────────────────────────────────────────────────────
const string SystemPrompt = """
    You are a research agent. Your job is to thoroughly research a topic provided by the user.

    Follow this workflow:
    1. Break the topic into 3-5 key sub-questions worth investigating.
    2. Use the SearchWeb tool to find information for each sub-question.
    3. Use the SaveNote tool to record every key finding as you go — include sources.
    4. When you have gathered enough information, use GetNotes to review everything.
    5. Produce a final, well-organized summary with clear headings and cited sources.

    Important rules:
    - Always save important findings as notes BEFORE writing the final summary.
    - Be thorough: make multiple searches with varied queries.
    - Be concise in notes, comprehensive in the final summary.
    """;

// ── Interactive loop ───────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║         🔍  AI Research Agent            ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.              ║");
Console.WriteLine("║  Type 'quit' to exit.                    ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic: ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"🔎 Researching: {topic}");
    Console.WriteLine("   This may take a moment while the agent searches and takes notes...\n");
    Console.ResetColor();

    notebook.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, SystemPrompt),
        new(ChatRole.User, $"Please research the following topic thoroughly: {topic}"),
    };

    try
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══════════════════════════════════════════");
        Console.WriteLine("  ✅  Research Complete");
        Console.WriteLine("═══════════════════════════════════════════\n");
        Console.ResetColor();

        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"❌ Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("Goodbye! 👋");

